% Generated by textlayout; units are micrometres.
close all; clear; clc;
physical_constants;
unit = 1e-6;
f_start = 3000000000; f_stop = 9000000000;
FDTD = InitFDTD('EndCriteria', 1e-5);
FDTD = SetGaussExcite(FDTD, (f_start+f_stop)/2, (f_stop-f_start)/2);
FDTD = SetBoundaryCond(FDTD, {'PML_8','PML_8','PML_8','PML_8','PML_8','PML_8'});
CSX = InitCSX();
CSX = AddMaterial(CSX, 'substrate', 'Epsilon', 11.9);
CSX = AddBox(CSX, 'substrate', 0, [-261 -200 -500], [261 1200 0]);
CSX = AddMetal(CSX, 'metal');
p0 = [-5 5 5 -5; 0 0 1000 1000];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p0);
p1 = [-61 -11 -11 -61; 0 0 1000 1000];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p1);
p2 = [11 61 61 11; 0 0 1000 1000];
CSX = AddPolygon(CSX, 'metal', 10, 'z', 0, p2);
mesh.x = SmoothMeshLines([-261 261], 20, 1.4);
mesh.y = SmoothMeshLines([-200 1200], 20, 1.4);
mesh.z = SmoothMeshLines([-500 0 100], 20, 1.4);
CSX = DefineRectGrid(CSX, unit, mesh);
[CSX, port{1}] = AddCPWPort(CSX, 999, 1, 'metal', [-5 0 -500], [5 100 50], 6, 'y', [1 0 0], 'ExcitePort', true);
[CSX, port{2}] = AddCPWPort(CSX, 999, 2, 'metal', [-5 900 -500], [5 1000 50], 6, 'y', [1 0 0]);
Sim_Path = 'openems_run'; Sim_CSX = 'model.xml';
[status, message] = rmdir(Sim_Path, 's'); mkdir(Sim_Path);
WriteOpenEMS(fullfile(Sim_Path, Sim_CSX), FDTD, CSX);
RunOpenEMS(Sim_Path, Sim_CSX);
freq = linspace(f_start, f_stop, 401);
port = calcPort(port, Sim_Path, freq);
s11 = port{1}.uf.ref ./ port{1}.uf.inc;
s21 = port{2}.uf.ref ./ port{1}.uf.inc;
fid = fopen('openems_result.s2p', 'w');
fprintf(fid, '# Hz S RI R 50\n');
for k=1:numel(freq)
  fprintf(fid, '%.12e %.12e %.12e %.12e %.12e %.12e %.12e %.12e %.12e\n', freq(k), real(s11(k)), imag(s11(k)), real(s21(k)), imag(s21(k)), real(s21(k)), imag(s21(k)), real(s11(k)), imag(s11(k)));
end
fclose(fid);
